/*! ics.js - GroupSync Modified Version (iOS/Android Support) */
var ics = function() {
    "use strict";
    if ("undefined" == typeof RegExp) return;
    var e = {
        Separator: "\r\n",
        // แก้ไข: เพิ่ม METHOD:PUBLISH เพื่อให้ iOS ยอมรับไฟล์ปฏิทิน
        Command: "BEGIN:VCALENDAR\r\nMETHOD:PUBLISH\r\nPRODID:-//GroupSync//NONSGML v1.0//EN\r\nVERSION:2.0\r\n",
        End: "END:VCALENDAR",
        Events: [],
        Calendar: function() {
            return this.Command + this.Events.join("") + this.End
        },
        addEvent: function(e, t, n, i, r) {
            if ("undefined" == typeof e || "undefined" == typeof t || "undefined" == typeof n || "undefined" == typeof i || "undefined" == typeof r) return !1;
            var a = new Date(i),
                o = new Date(r),
                // แก้ไข: Format วันที่ให้เป็นมาตรฐานสากลที่ iOS/Android อ่านออก
                s = ("0000" + a.getFullYear()).slice(-4) + ("00" + (a.getMonth() + 1)).slice(-2) + ("00" + a.getDate()).slice(-2) + "T" + ("00" + a.getHours()).slice(-2) + ("00" + a.getMinutes()).slice(-2) + ("00" + a.getSeconds()).slice(-2),
                c = ("0000" + o.getFullYear()).slice(-4) + ("00" + (o.getMonth() + 1)).slice(-2) + ("00" + o.getDate()).slice(-2) + "T" + ("00" + o.getHours()).slice(-2) + ("00" + o.getMinutes()).slice(-2) + ("00" + o.getSeconds()).slice(-2),
                // แก้ไข: ลบ ;VALUE=DATE-TIME ออก เพราะ iOS รุ่นใหม่จะมองว่ามัน Error
                u = "BEGIN:VEVENT\r\nUID:" + Date.now() + "@groupsync\r\nCLASS:PUBLIC\r\nDESCRIPTION:" + t + "\r\nDTSTAMP:" + s + "Z\r\nDTSTART:" + s + "\r\nDTEND:" + c + "\r\nLOCATION:" + n + "\r\nSUMMARY:" + e + "\r\nTRANSP:TRANSPARENT\r\nEND:VEVENT\r\n";
            return this.Events.push(u), u
        },
        download: function(e) {
            if (this.Events.length < 1) return !1;
            e = "undefined" != typeof e ? e : "calendar";
            var t = this.Calendar(),
                n = new Blob([t], {
                    type: "text/calendar;charset=utf-8"
                });
            return saveAs(n, e + ".ics"), t
        }
    };
    return e
};

// ส่วนของ saveAs ที่ปรับปรุงให้รองรับ Mobile Browser ได้ดีขึ้น
if ("undefined" == typeof saveAs) var saveAs = function(e, t) {
    "use strict";
    var n = e.type,
        i = new Blob([e], { type: n }),
        r = URL.createObjectURL(i),
        a = document.createElement("a");
    a.download = t;
    a.href = r;
    a.style.display = "none";
    document.body.appendChild(a);
    a.click();
    setTimeout(function() {
        document.body.removeChild(a);
        URL.revokeObjectURL(r)
    }, 100)
};